	klog.InitFlags(flag.CommandLine)
	flag.Parse()

	namespace := flag.String("namespace", "", "Namespace to watch for idle sandboxes")
	expirationTimeout := flag.Duration("expiration-timeout", 15*time.Minute, "Timeout before idle sandbox is cleaned up")
	healthProbeAddr := flag.String("health-probe-bind-address", ":8081", "The address the healthz probe binds to")
	metricsAddr := flag.String("metrics-bind-address", ":8082", "The address the metrics endpoint binds to")
	syncInterval := flag.Duration("sync-interval", 1*time.Minute, "Interval between reconciliation cycles")

	cfg, err := config.GetConfigOrDie()
	if err != nil {
		klog.Exitf("Failed to get kubeconfig: %v", err)
	}

	restConfig := &rest.Config{
		Host: cfg.Host,
	}
	*restConfig = *cfg

	mgr, err := manager.New(restConfig, manager.Options{
		Scheme: scheme,
		Metrics: server.Options{
			BindAddress: *metricsAddr,
		},
		HealthProbeBindAddress: *healthProbeAddr,
	})
	if err != nil {
		klog.Exitf("Failed to create manager: %v", err)
	}

	kubeClient, err := kubernetes.NewForConfig(restConfig)
	if err != nil {
		klog.Exitf("Failed to create kubernetes client: %v", err)
	}

