from typing import Dict, Optional

import requests

from agentcube import exceptions


class ControlPlaneClient:
    def __init__(self, workload_manager_url: str, auth_token: Optional[str] = None):
        self.workload_manager_url = workload_manager_url.rstrip("/")
        self.auth_token = auth_token
        self.session = requests.Session()
        if self.auth_token:
            self.session.headers["Authorization"] = f"Bearer {self.auth_token}"

    def create_session(
        self,
        name: str,
        namespace: str,
        metadata: Optional[Dict[str, str]] = None,
        ttl: int = 3600,
    ) -> str:
        url = f"{self.workload_manager_url}/v1/code-interpreter"
        payload = {
            "name": name,
            "namespace": namespace,
            "ttl": ttl,
        }
        if metadata:
            payload["metadata"] = metadata

        try:
            resp = self.session.post(url, json=payload, timeout=30)
            resp.raise_for_status()
            data = resp.json()
            return data.get("session_id")
        except requests.RequestException as e:
            raise exceptions.SessionError(f"Failed to create session: {e}")

    def delete_session(self, session_id: str) -> bool:
        url = f"{self.workload_manager_url}/v1/code-interpreter/{session_id}"

        try:
            resp = self.session.delete(url, timeout=30)
            resp.raise_for_status()
            return True
        except requests.RequestException as e:
            raise exceptions.SessionError(f"Failed to delete session: {e}")

    def get_session(self, session_id: str) -> Dict:
        url = f"{self.workload_manager_url}/v1/code-interpreter/{session_id}"

        try:
            resp = self.session.get(url, timeout=30)
            resp.raise_for_status()
            return resp.json()
        except requests.RequestException as e:
            raise exceptions.SessionError(f"Failed to get session: {e}")

    def list_sessions(self, namespace: str) -> Dict:
        url = f"{self.workload_manager_url}/v1/code-interpreter"
        params = {"namespace": namespace}

        try:
            resp = self.session.get(url, params=params, timeout=30)
            resp.raise_for_status()
            return resp.json()
        except requests.RequestException as e:
            raise exceptions.SessionError(f"Failed to list sessions: {e}")

    def close(self):
        self.session.close()

